#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return 1; // Connection failed
  }

  auto conn = conn_result.value();

  // Begin transaction
  auto transaction_result = sqlgen::begin_transaction(conn);
  if (!transaction_result) {
    return 1; // Transaction start failed
  }

  auto transaction = transaction_result.value();

  try {
    // Create delete statement with condition
    auto delete_stmt = sqlgen::delete_from<User> 
                      | sqlgen::where("last_login"_c < "2025-01-01");

    // Execute the delete operation
    auto delete_result = delete_stmt(transaction);
    if (!delete_result) {
      // Rollback on failure
      transaction->rollback();
      return 1;
    }

    // Commit the transaction
    auto commit_result = sqlgen::commit(transaction);
    if (!commit_result) {
      return 1; // Commit failed
    }

    return 0; // Success

  } catch (...) {
    // Rollback on exception
    transaction->rollback();
    return 1;
  }
}

} // namespace delete_inactive_users
```

