#include <gtest/gtest.h>
#include <vector>
#include <string>

#include "query_course_enrollment_stats.hpp"

namespace query_course_enrollment_stats {

/**
 * Test Case: Test course enrollment stats query
 * 
 * Test Scenario:
 * - Create Course and Enrollment tables
 * - Insert sample data (including course with no students, students with no grades)
 * - Call query_course_enrollment_stats
 * - Verify counts and averages
 */
TEST(sqlite, query_course_enrollment_stats) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Cleanup
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Enrollment>(conn);
  drop<Course>(conn);

  // 1. Create tables and insert data
  create_table<Course>(conn);
  create_table<Enrollment>(conn);

  Course c1{.course_id = 1, .title = "Math 101"};
  Course c2{.course_id = 2, .title = "History 101"};
  Course c3{.course_id = 3, .title = "Physics 101"};
  insert(conn, std::vector{c1, c2, c3});

  // Math 101: 2 students, grades 90.0 and 80.0 (avg 85.0)
  Enrollment e1{.enrollment_id = 1, .course_id = 1, .grade = 90.0f};
  Enrollment e2{.enrollment_id = 2, .course_id = 1, .grade = 80.0f};

  // History 101: 1 student, grade NULL (avg NULL)
  Enrollment e3{.enrollment_id = 3, .course_id = 2, .grade = std::nullopt};

  // Physics 101: 0 students (count 0, avg NULL)

  insert(conn, std::vector{e1, e2, e3});

  // 2. Call query function
  auto stats = query_course_enrollment_stats();

  // 3. Verify results
  // Note: Order depends on group by, likely ordered by id implicitly or undefined.
  // We can sort or find by title.

  auto find_stat = [&](const std::string& title) -> std::optional<CourseStats> {
      for (const auto& s : stats) {
          if (s.title == title) return s;
      }
      return std::nullopt;
  };

  auto s1 = find_stat("Math 101");
  ASSERT_TRUE(s1.has_value());
  EXPECT_EQ(s1->student_count, 2);
  ASSERT_TRUE(s1->avg_grade.has_value());
  EXPECT_DOUBLE_EQ(s1->avg_grade.value(), 85.0);

  auto s2 = find_stat("History 101");
  ASSERT_TRUE(s2.has_value());
  EXPECT_EQ(s2->student_count, 1);
  EXPECT_FALSE(s2->avg_grade.has_value()); // Average of NULLs is NULL usually, or depends on DB. SQLite avg(NULL) is NULL.

  auto s3 = find_stat("Physics 101");
  ASSERT_TRUE(s3.has_value());
  EXPECT_EQ(s3->student_count, 1);
  EXPECT_FALSE(s3->avg_grade.has_value());
}

}  // namespace query_course_enrollment_stats

