#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Create tables and insert data
  sqlgen::write(conn, depts).value();
  sqlgen::write(conn, emps).value();

  // Define table aliases
  auto d = "d"_t1;
  auto e = "e"_t2;

  // INNER JOIN: Employees with assigned departments
  auto inner_query = sqlgen::select_from<Department>(d["department_name"], e["first_name"], e["last_name"], e["salary"])
      | sqlgen::inner_join<Employee>(d["department_id"] == e["department_id"]);

  auto inner_results = inner_query(conn).to<std::vector<JoinResult>>().value();

  // LEFT JOIN: All employees (even without departments)
  auto left_query = sqlgen::select_from<Employee>(d["department_name"], e["first_name"], e["last_name"], e["salary"])
      | sqlgen::left_join<Department>(e["department_id"] == d["department_id"]);

  auto left_results = left_query(conn).to<std::vector<JoinResult>>().value();

  // RIGHT JOIN: All departments (even without employees)
  auto right_query = sqlgen::select_from<Employee>(d["department_name"], e["first_name"], e["last_name"], e["salary"])
      | sqlgen::right_join<Department>(e["department_id"] == d["department_id"]);

  auto right_results = right_query(conn).to<std::vector<JoinResult>>().value();

  // FULL JOIN: All employees and departments
  auto full_query = sqlgen::select_from<Employee>(d["department_name"], e["first_name"], e["last_name"], e["salary"])
      | sqlgen::full_join<Department>(e["department_id"] == d["department_id"]);

  auto full_results = full_query(conn).to<std::vector<JoinResult>>().value();

  // Return comprehensive analysis
  return JoinAnalysis{
      .inner_join_results = inner_results,
      .left_join_results = left_results,
      .right_join_results = right_results,
      .full_join_results = full_results
  };
}

}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to connect to "test_db.sqlite"
2. **Table Creation & Data Insertion**: Uses `sqlgen::write()` to create tables and insert department/employee data
3. **Table Aliases**: Uses `sqlgen::literals` to define table aliases "d" (Department) and "e" (Employee)
4. **Join Operations**:
   - **INNER JOIN**: Matches employees with their departments
   - **LEFT JOIN**: Includes all employees, showing NULL for departments without matching employees
   - **RIGHT JOIN**: Includes all departments, showing NULL for employees without matching departments
   - **FULL JOIN**: Combines all records from both tables, showing NULLs where no matches exist
5. **Result Collection**: Each join result is converted to `std::vector<JoinResult>` using `.to<std::vector<JoinResult>>()`
6. **Error Handling**: Uses `.value()` to extract results from `rfl::Result` types (assumes successful operations)

The implementation follows sqlgen's fluent API pattern and correctly handles the optional nature of join results through `std::optional` fields in the `JoinResult` structure.

